 1	import React, { FC } from 'react';
 2	
 3	import { modelToGroupVersionKind } from '@kubevirt-ui/kubevirt-api/console';
 4	import { V1InstancetypeMatcher } from '@kubevirt-ui/kubevirt-api/kubevirt';
 5	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 6	import { getInstanceTypeModelFromMatcher } from '@kubevirt-utils/resources/instancetype/helper';
 7	import useInstanceType from '@kubevirt-utils/resources/vm/hooks/useInstanceType';
 8	import { ResourceLink } from '@openshift-console/dynamic-plugin-sdk';
 9	import { Skeleton, TextListItem, TextListItemVariants } from '@patternfly/react-core';
10	
11	type InstanceTypeConfigurationProps = {
12	  itMatcher: V1InstancetypeMatcher;
13	};
14	
15	const InstanceTypeConfiguration: FC<InstanceTypeConfigurationProps> = ({ itMatcher }) => {
16	  const { t } = useKubevirtTranslation();
17	  const { instanceType, instanceTypeLoaded } = useInstanceType(itMatcher);
18	
19	  return (
20	    <>
21	      <TextListItem className="text-muted" component={TextListItemVariants.dt}>
22	        {t('InstanceType')}
23	      </TextListItem>
24	
25	      <TextListItem component={TextListItemVariants.dd}>
26	        {instanceTypeLoaded ? (
27	          <ResourceLink
28	            groupVersionKind={modelToGroupVersionKind(getInstanceTypeModelFromMatcher(itMatcher))}
29	            namespace={instanceType.metadata.namespace}
30	          >
31	            {instanceType.metadata.name}
32	          </ResourceLink>
33	        ) : (
34	          <Skeleton className="pf-m-width-sm" />
35	        )}
36	      </TextListItem>
37	    </>
38	  );
39	};
40	
41	export default InstanceTypeConfiguration;

